import{_ as o,o as t,c as a,ag as s}from"./chunks/framework.DL0AyVxm.js";const p=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"guide/introduction.md","filePath":"guide/introduction.md"}'),i={name:"guide/introduction.md"};function n(r,e,l,d,c,u){return t(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><h2 id="the-problem" tabindex="-1">The Problem <a class="header-anchor" href="#the-problem" aria-label="Permalink to &quot;The Problem&quot;">​</a></h2><p>Claude Code is incredibly powerful, but getting the most out of it requires a lot of up-front configuration. You need agents for different review tasks, skills that teach Claude your project&#39;s conventions, slash commands for session management, hooks for auto-formatting, and a carefully structured <code>CLAUDE.md</code> that keeps Claude focused without overwhelming its context.</p><p>Most people skip all of this. They open Claude Code, type a prompt, and get decent results. But &quot;decent&quot; leaves a lot on the table. Boris Cherny, the creator of Claude Code at Anthropic, published <a href="https://www.howborisusesclaudecode.com" target="_blank" rel="noreferrer">53 tips</a> for using Claude Code professionally. Those tips cover everything from session lifecycle to subagent orchestration to context management. Implementing all 53 by hand takes hours of careful setup work.</p><h2 id="the-solution" tabindex="-1">The Solution <a class="header-anchor" href="#the-solution" aria-label="Permalink to &quot;The Solution&quot;">​</a></h2><p>Worclaude automates that setup. Run one command, answer a few questions about your project, and you get a complete professional workflow installed in your repository. Every file it generates is derived from Boris Cherny&#39;s 53 tips.</p><p>Worclaude is a Node.js CLI tool (v1.1.0) that you install globally and run in any project directory. It examines your project, asks what kind of software you are building, and scaffolds the right combination of agents, skills, commands, hooks, and permissions.</p><h2 id="what-you-get" tabindex="-1">What You Get <a class="header-anchor" href="#what-you-get" aria-label="Permalink to &quot;What You Get&quot;">​</a></h2><p>When you run <code>worclaude init</code>, the following components are installed into your project:</p><h3 id="agents-23-total" tabindex="-1">Agents (23 total) <a class="header-anchor" href="#agents-23-total" aria-label="Permalink to &quot;Agents (23 total)&quot;">​</a></h3><p>Agents are specialized Claude instances, each with a specific model and purpose. You always get the 5 <strong>universal agents</strong>:</p><ul><li><strong>plan-reviewer</strong> (Opus) -- Reviews implementation plans like a staff engineer. Challenges assumptions and finds gaps.</li><li><strong>code-simplifier</strong> (Sonnet, worktree) -- Eliminates duplication, simplifies complex logic, enforces consistency.</li><li><strong>test-writer</strong> (Sonnet, worktree) -- Writes comprehensive tests: unit, integration, edge cases, error paths.</li><li><strong>build-validator</strong> (Haiku) -- Runs the build, tests, and linter. Reports failures without fixing them.</li><li><strong>verify-app</strong> (Sonnet, worktree) -- Tests the running application end-to-end against the specification.</li></ul><p>On top of these, you choose from 18 <strong>optional agents</strong> across 6 categories (Backend, Frontend, DevOps, Quality, Documentation, Data/AI). Worclaude recommends agents based on your project type, so you do not have to guess.</p><h3 id="skills-12-total" tabindex="-1">Skills (12 total) <a class="header-anchor" href="#skills-12-total" aria-label="Permalink to &quot;Skills (12 total)&quot;">​</a></h3><p>Skills are knowledge files that Claude loads on demand. They teach Claude how your project works without bloating the main context. You get 9 <strong>universal skills</strong> covering context management, git conventions, planning, session handoffs, prompt engineering, verification, testing, CLAUDE.md maintenance, and subagent usage. You also get 3 <strong>template skills</strong> (backend-conventions, frontend-design-system, project-patterns) that serve as placeholders for your project-specific details.</p><h3 id="slash-commands-10-total" tabindex="-1">Slash Commands (10 total) <a class="header-anchor" href="#slash-commands-10-total" aria-label="Permalink to &quot;Slash Commands (10 total)&quot;">​</a></h3><p>Commands give you a session lifecycle. <code>/start</code> reads your progress file and orients Claude. <code>/end</code> updates progress and writes a handoff document. <code>/commit-push-pr</code> stages, commits, pushes, and opens a pull request. <code>/verify</code> runs your full test and build pipeline. <code>/setup</code> interviews you about your project and fills in all the template files automatically. The full set: <code>/start</code>, <code>/end</code>, <code>/commit-push-pr</code>, <code>/review-plan</code>, <code>/techdebt</code>, <code>/verify</code>, <code>/compact-safe</code>, <code>/status</code>, <code>/update-claude-md</code>, <code>/setup</code>.</p><h3 id="hooks" tabindex="-1">Hooks <a class="header-anchor" href="#hooks" aria-label="Permalink to &quot;Hooks&quot;">​</a></h3><p>Three hooks are installed automatically:</p><ul><li><strong>PostToolUse (Write/Edit)</strong> -- Auto-formats code after every file change, using the right formatter for your tech stack.</li><li><strong>PostCompact</strong> -- Re-reads <code>CLAUDE.md</code> and <code>PROGRESS.md</code> after context compaction, so Claude never loses orientation.</li><li><strong>Stop</strong> -- Sends an OS notification when Claude finishes and needs your attention.</li></ul><h3 id="permissions-and-sandbox" tabindex="-1">Permissions and Sandbox <a class="header-anchor" href="#permissions-and-sandbox" aria-label="Permalink to &quot;Permissions and Sandbox&quot;">​</a></h3><p>A comprehensive <code>settings.json</code> with pre-approved permissions for common development tools (git, build tools, formatters, file operations) so Claude does not constantly ask for permission. Sandbox mode is enabled with auto-allow for structural safety.</p><h3 id="claude-md" tabindex="-1">CLAUDE.md <a class="header-anchor" href="#claude-md" aria-label="Permalink to &quot;CLAUDE.md&quot;">​</a></h3><p>A lean, structured <code>CLAUDE.md</code> (under 50 lines) that follows the progressive disclosure pattern. It points to skills for detail instead of trying to contain everything. Includes sections for Key Files, Tech Stack, Commands, Skills, Session Protocol, Critical Rules, and Gotchas.</p><h2 id="for-experienced-claude-code-users" tabindex="-1">For Experienced Claude Code Users <a class="header-anchor" href="#for-experienced-claude-code-users" aria-label="Permalink to &quot;For Experienced Claude Code Users&quot;">​</a></h2><p>If you already know Boris Cherny&#39;s tips or have read <a href="https://www.howborisusesclaudecode.com" target="_blank" rel="noreferrer">howborisusesclaudecode.com</a>, Worclaude codifies those patterns into installable files. You can think of it as a starter kit that gives you a solid baseline. After installation, you customize everything to fit your specific project.</p><p>The agents follow Anthropic&#39;s recommended model assignments. Skills follow Thariq&#39;s skill authoring standards (skip the obvious, build gotchas sections, use progressive disclosure). Commands implement the session lifecycle pattern that Boris describes.</p><h2 id="what-worclaude-is-not" tabindex="-1">What Worclaude Is NOT <a class="header-anchor" href="#what-worclaude-is-not" aria-label="Permalink to &quot;What Worclaude Is NOT&quot;">​</a></h2><p>Worclaude is a <strong>scaffolding tool</strong>. It is not a replacement for Claude Code itself. It does not run Claude, manage sessions, or interact with the AI in any way. What it does is set up the configuration files that make Claude Code work at its best.</p><p>After Worclaude finishes, you still need to:</p><ol><li>Launch Claude Code yourself (<code>claude --worktree --tmux</code>)</li><li>Run <code>/setup</code> to fill in project-specific details through a guided interview</li><li>Write your <code>SPEC.md</code> with your project&#39;s requirements</li><li>Do the actual development work with Claude</li></ol><p>Worclaude handles the boilerplate so you can focus on building.</p><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="/Worclaude/guide/getting-started.html">Getting Started</a> -- Full walkthrough of installing and running Worclaude</li><li><a href="/Worclaude/guide/existing-projects.html">Existing Projects</a> -- How Worclaude handles projects that already have Claude Code configured</li><li><a href="/Worclaude/guide/upgrading.html">Upgrading</a> -- Keeping your workflow up to date</li><li><a href="/Worclaude/guide/workflow-tips.html">Workflow Tips</a> -- Best practices for working with Claude Code after setup</li></ul>',34)])])}const m=o(i,[["render",n]]);export{p as __pageData,m as default};
